sql:
SELECT COUNT(DISTINCT tourney_singles_winner) AS total_players
FROM tournaments
WHERE tourney_category = 'Grand Slam';

SELECT tourney_singles_winner
FROM tournaments
WHERE tourney_name = 'French Open' AND tourney_year_id = '1968';

SELECT tourney_name
FROM tournaments
WHERE tourney_slug = 'australian-open' AND tourney_year_id LIKE '1968%';

external_knowledge:
External knowledge:
- '581' refers to a specific tournament year identifier; 
- 'Grand Slam' is a category of high-profile tennis tournaments; 
- Top-ranked players imply those with the highest ranking.

The concept of "most singles titles" implies that there may be multiple players who have won the same maximum number of titles. In such cases, all of these players will be included in the results; 
Singles titles refer to the number of times a player has won a singles tournament; 
A player winning a singles title means they have emerged victorious in a singles competition.

sql:
SELECT SUM(player_career_titles) AS total_titles
FROM players
WHERE player_country = 'Australia' OR player_career_high = 1;

SELECT 
  (SELECT COUNT(*) FROM players) AS total_players,
  (SELECT AVG(CAST(tourney_prize_money AS REAL)) FROM tournaments) AS average_prize_money;

SELECT AVG(p.player_career_prize_money) AS avg_career_prize_money
FROM players p
JOIN tournaments t ON p.player_id = t.tourney_singles_winner
WHERE t.tourney_year_id = (
  SELECT MIN(tourney_year_id) FROM tournaments
);
